if ( ! function_exists( 'marconi_servizio_icon_svg' ) ) {
	/**
	 * Return inline SVG markup for a service watermark icon, or '' if unknown/empty.
	 */
	function marconi_servizio_icon_svg( $key, $class = 'svc-wm' ) {
		$key = trim( (string) $key );
		if ( $key === '' ) {
			return '';
		}
		$paths = marconi_servizio_icon_paths();
		if ( ! isset( $paths[ $key ] ) ) {
			return '';
		}
		return '<svg class="' . esc_attr( $class ) . '" viewBox="0 0 24 24" aria-hidden="true" focusable="false">' . $paths[ $key ] . '</svg>';
	}
}
